# --- Cardinality Explosion Prevention ---

# Configuration limits
MAX_UNIQUE_USERS = 500
MAX_UNIQUE_PATHS = 200
MAX_UNIQUE_SESSIONS = 1000
MAX_METRIC_COMBINATIONS = 5000
COMBINATION_TTL_SECONDS = 3600  # 1 hour TTL for stale combinations

# Global metrics (no high-cardinality labels)
TOTAL_REQUESTS = Counter(
    'http_requests_total',
    'Total HTTP requests (global)',
    ['method', 'status_code']
)

DROPPED_METRICS = Counter(
    'http_requests_dropped_labels_total',
    'Requests where detailed labels were dropped due to cardinality limits',
    ['reason']
)

ACTIVE_COMBINATIONS = Gauge(
    'http_request_tracking_active_combinations',
    'Number of currently tracked user-path combinations'
)

# Detailed per-user-path metrics (with cardinality control)
DETAILED_REQUESTS = Counter(
    'http_requests_detailed_total',
    'HTTP requests with detailed labels (cardinality controlled)',
    ['user_id', 'session_id', 'path', 'method']
)

DETAILED_LATENCY = Histogram(
    'http_request_duration_seconds_detailed',
    'Request latency with detailed labels (cardinality controlled)',
    ['user_id', 'path', 'method'],
    buckets=[0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0]
)


class CardinalityGuard:
    """Prevents metrics cardinality explosion by tracking and limiting unique label combinations."""

    def __init__(
        self,
        max_users=MAX_UNIQUE_USERS,
        max_paths=MAX_UNIQUE_PATHS,
        max_sessions=MAX_UNIQUE_SESSIONS,
        max_combinations=MAX_METRIC_COMBINATIONS,
        ttl_seconds=COMBINATION_TTL_SECONDS,
    ):
        self.max_users = max_users
        self.max_paths = max_paths
        self.max_sessions = max_sessions
        self.max_combinations = max_combinations
        self.ttl_seconds = ttl_seconds

        self._lock = threading.Lock()

        # Track known values
        self._known_users = OrderedDict()      # user_id -> last_seen_timestamp
        self._known_paths = OrderedDict()      # path -> last_seen_timestamp
        self._known_sessions = OrderedDict()   # session_id -> last_seen_timestamp
        self._known_combinations = OrderedDict()  # (user_id, path) -> last_seen_timestamp

        # Normalized/overflow buckets
        self._overflow_user = "__overflow_user__"
        self._overflow_path = "__overflow_path__"
        self._overflow_session = "__overflow_session__"

        # Start background cleanup thread
        self._cleanup_thread = threading.Thread(target=self._periodic_cleanup, daemon=True)
        self._cleanup_thread.start()

    def _evict_stale(self, od, now):
        """Remove entries older than TTL from an OrderedDict."""
        keys_to_remove = []
        for key, ts in od.items():
            if now - ts > self.ttl_seconds:
                keys_to_remove.append(key)
            else:
                break  # OrderedDict is ordered by insertion/update time
        for key in keys_to_remove:
            del od[key]

    def _periodic_cleanup(self):
        """Periodically clean up stale entries."""
        while True:
            time.sleep(60)
            self._cleanup()

    def _cleanup(self):
        now = time.time()
        with self._lock:
            self._evict_stale(self._known_users, now)
            self._evict_stale(self._known_paths, now)
            self._evict_stale(self._known_sessions, now)
            self._evict_stale(self._known_combinations, now)
            ACTIVE_COMBINATIONS.set(len(self._known_combinations))

    def _normalize_path(self, path):
        """Normalize paths to reduce cardinality.
        
        Replaces numeric and UUID-like path segments with placeholders.
        E.g., /api/users/12345/orders/abc-def -> /api/users/:id/orders/:id
        """
        if not path:
            return "/"

        import re
        segments = path.strip("/").split("/")
        normalized = []
        for segment in segments:
            # Replace pure numeric segments
            if re.match(r'^\d+$', segment):
                normalized.append(':id')
            # Replace UUID-like segments
            elif re.match(r'^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$', segment):
                normalized.append(':uuid')
            # Replace hex-like long strings (e.g., MongoDB ObjectIds)
            elif re.match(r'^[0-9a-fA-F]{24,}$', segment):
                normalized.append(':hex_id')
            else:
                normalized.append(segment)
        return "/" + "/".join(normalized)

    def check_and_register(self, user_id, session_id, path, method):
        """Check if this combination is allowed and return safe label values.
        
        Returns:
            tuple: (safe_user_id, safe_session_id, safe_path, is_detailed)
                   is_detailed=False means labels were bucketed into overflow.
        """
        now = time.time()
        normalized_path = self._normalize_path(path)

        safe_user = user_id
        safe_session = session_id
        safe_path = normalized_path
        is_detailed = True

        with self._lock:
            # Evict stale entries first
            self._evict_stale(self._known_users, now)
            self._evict_stale(self._known_paths, now)
            self._evict_stale(self._known_sessions, now)
            self._evict_stale(self._known_combinations, now)

            # Check user cardinality
            if user_id in self._known_users:
                self._known_users[user_id] = now
                # Move to end for LRU
                self._known_users.move_to_end(user_id)
            elif len(self._known_users) < self.max_users:
                self._known_users[user_id] = now
            else:
                safe_user = self._overflow_user
                is_detailed = False
                DROPPED_METRICS.labels(reason='user_limit').inc()

            # Check path cardinality
            if normalized_path in self._known_paths:
                self._known_paths[normalized_path] = now
                self._known_paths.move_to_end(normalized_path)
            elif len(self._known_paths) < self.max_paths:
                self._known_paths[normalized_path] = now
            else:
                safe_path = self._overflow_path
                is_detailed = False
                DROPPED_METRICS.labels(reason='path_limit').inc()

            # Check session cardinality
            if session_id in self._known_sessions:
                self._known_sessions[session_id] = now
                self._known_sessions.move_to_end(session_id)
            elif len(self._known_sessions) < self.max_sessions:
                self._known_sessions[session_id] = now
            else:
                safe_session = self._overflow_session
                is_detailed = False
                DROPPED_METRICS.labels(reason='session_limit').inc()

            # Check combination cardinality
            combo_key = (safe_user, safe_path)
            if combo_key in self._known_combinations:
                self._known_combinations[combo_key] = now
                self._known_combinations.move_to_end(combo_key)
            elif len(self._known_combinations) < self.max_combinations:
                self._known_combinations[combo_key] = now
            else:
                safe_user = self._overflow_user
                safe_path = self._overflow_path
                safe_session = self._overflow_session
                is_detailed = False
                DROPPED_METRICS.labels(reason='combination_limit').inc()

            ACTIVE_COMBINATIONS.set(len(self._known_combinations))

        return safe_user, safe_session, safe_path, is_detailed

    def get_stats(self):
        """Return current cardinality stats."""
        with self._lock:
            return {
                'unique_users': len(self._known_users),
                'max_users': self.max_users,
                'unique_paths': len(self._known_paths),
                'max_paths': self.max_paths,
                'unique_sessions': len(self._known_sessions),
                'max_sessions': self.max_sessions,
                'unique_combinations': len(self._known_combinations),
                'max_combinations': self.max_combinations,
            }


# Global cardinality guard instance
cardinality_guard = CardinalityGuard()


def track_request(user_id, session_id, path, method, status_code, duration):
    """Track an HTTP request with cardinality-safe labels."""
    # Always increment global counter (low cardinality)
    TOTAL_REQUESTS.labels(method=method, status_code=str(status_code)).inc()

    # Get safe labels from cardinality guard
    safe_user, safe_session, safe_path, is_detailed = cardinality_guard.check_and_register(
        user_id=user_id,
        session_id=session_id,
        path=path,
        method=method,
    )

    # Increment detailed counter with safe labels
    DETAILED_REQUESTS.labels(
        user_id=safe_user,
        session_id=safe_session,
        path=safe_path,
        method=method,
    ).inc()

    # Record latency (without session_id to reduce combinations)
    DETAILED_LATENCY.labels(
        user_id=safe_user,
        path=safe_path,
        method=method,
    ).observe(duration)


# --- Flask Middleware ---

@app.before_request
def before_request_handler():
    request._start_time = time.time()


@app.after_request
def after_request_handler(response):
    duration = time.time() - getattr(request, '_start_time', time.time())

    # Extract user_id and session_id from headers, query params, or defaults
    user_id = (
        request.headers.get('X-User-ID')
        or request.args.get('user_id')
        or 'anonymous'
    )
    session_id = (
        request.headers.get('X-Session-ID')
        or request.args.get('session_id')
        or 'no_session'
    )

    track_request(
        user_id=user_id,
        session_id=session_id,
        path=request.path,
        method=request.method,
        status_code=response.status_code,
        duration=duration,
    )

    return response


